VALUES
  ('cpa-moex-01718', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '紐約公司於X1年1月1日與洋基公司簽訂技術合約，授權洋基公司使用紐約公司之某項技術，合約 期限為9年，不得展延。紐約公司於X5年1月1日以現金$500,000吸收合併洋基公司，當日洋基公 司可辨認淨資產之公允價值包括：與紐約公司所簽訂之技術合約$100,000、其他可辨認資產$740,000 及負債$320,000。該技術合約條件對紐約公司而言較市場條件不利，不利之金額為$80,000。合約規 定不得提前解約且紐約公司於收購日前並未針對此不利狀況認列任何資產或負債。紐約公司有關之 會計處理，下列敘述何者正確？', '["X5年1月1日應認列之技術合約結清損失$80,000", "X5年1月1日應認列「再取回之權利－技術合約」$80,000", "X5年1月1日應認列之合併商譽為$80,000", "X5年1月1日企業合併之移轉對價為$520,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01719', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，X6年1月1日紐約公司將收購日所取回之技術合約以$100,000售予尼克公司。當日紐約公 司應認列出售該技術合約之（損）益為何？', '["$80,000", "$60,000", "$20,000", "$10,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01720', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司持有乙公司90%股權，乙公司持有丙公司70%股權，聯屬公司間投資均以投資日股權淨值取 得。本年度各公司個別淨利如下：甲公司$120,000；乙公司$60,000；丙公司$30,000。試問合併淨利 與非控制權益淨利為何？', '["$180,900與$29,100", "$192,900與$17,100", "$195,000與$15,000", "$198,900與$11,100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01721', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '書豪公司於X1年底以$150,000的價格出售機器予其持股80%的建明公司。該機器對書豪公司而言，成 本為$200,000，出售當時的帳面金額為$120,000，該機器尚有5年的耐用年限，採直線法提列折舊。書 豪公司對該項投資採權益法處理，此一公司間銷售對X1年的投資收益及書豪公司帳列淨利的影響為 何？', '["投資收益減少$30,000，不影響書豪公司帳列淨利", "投資收益與書豪公司帳列淨利同時減少$30,000", "投資收益減少$24,000，書豪公司帳列淨利增加$6,000", "投資收益減少$24,000，書豪公司帳列淨利增加$24,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01722', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日分別持有乙公司與丙公司60%與30%之股權，乙公司於同日持有丙公司40% 股權，前述各項投資皆採權益法處理，且於該日均無未攤銷差額。甲、乙與丙三家公司於X1年之個 別淨利（不含投資收益或股利收入）分別為$1,000,000、$500,000與$200,000。丙公司於X1年10月 1日以$200,000銷售商品予甲公司，該批商品於丙公司帳列存貨成本為$150,000。截至X1年底，甲 公司購自丙公司該批存貨仍有半數尚未出售予外部企業。試問在X1年甲公司及其子公司之合併損益 表上，非控制權益淨利為：', '["$228,000", "$252,500", "$280,500", "$292,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01723', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '大為公司定期銷售商品予其持股 90%之子公司小城公司。小城公司 X1 年底的期末存貨中，包含 $40,000之未實現銷貨毛利，而X2年底的期末存貨中，則包含$30,000之未實現銷貨毛利，則下列敘 述何者正確？', '["X2年大為公司和小城公司個別銷貨成本的合計數將小於合併銷貨成本", "X2年大為公司和小城公司個別銷貨收入的合計數將小於合併銷貨收入", "X2年底大為公司和小城公司個別存貨的合計數將小於合併存貨", "X2年大為公司和小城公司個別銷貨毛利的合計數將小於合併銷貨毛利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01724', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日以$600,000取得乙公司60%之股權，當日乙公司權益包括股本$500,000（每 股面額$10），保留盈餘$400,000，除建築物低估$50,000（剩餘效益年限為 10 年，採直線法折舊） 外，當日乙公司其他可辨認資產與負債之帳面金額均等於公允價值。甲公司依可辨認淨資產之比例 衡量非控制權益。X2年12月31日乙公司之權益包括股本$500,000，保留盈餘$610,000。乙公司於 X3年1月1日以每股$23向非控制權益股東買回10,000股自家股份。甲公司採權益法處理其對乙公 司之投資。試問在X3年1月1日乙公司買回庫藏股後，甲公司帳上「投資乙公司」之帳戶餘額為：', '["$690,000", "$696,000", "$720,000", "$726,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01725', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於 X1 年 1 月 1 日以$480,000 取得上市公司乙公司 40%之股權，當日乙公司之權益為 $1,000,000，且其所有可辨認資產與負債之帳面金額均等於公允價值。甲公司於X1年7月1日另以 市價$500,000 額外取得乙公司 40%之股權，當日乙公司所有可辨認資產與負債中，除了存貨高估 $45,000外，其他可辨認資產與負債之帳面金額均等於公允價值，該批存貨於X1年12月31日仍有 1/3 尚未出售。甲公司依可辨認淨資產比例衡量非控制權益。乙公司 X1 年之淨利為$180,000，係於 年度中平均賺得。乙公司於X1年6月10日發放現金股利$45,000。甲公司採權益法處理該項投資。 試問X1年12月31日合併商譽與投資乙公司之帳戶餘額分別為：', '["$180,000與$1,094,000", "$200,000與$1,048,000", "$198,000與$1,094,000", "$200,000與$1,096,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01726', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年初以$760,000取得上市公司乙公司80%之股權，當日乙公司權益為$900,000（含 股本$300,000，保留盈餘$600,000），除設備（剩餘耐用年限為5年，採直線法提列折舊）帳面 金額低估$50,000外，當日乙公司其他可辨認資產與負債之帳面金額均等於公允價值。甲公司依可 辨認淨資產之比例衡量非控制權益。X2年12月31日乙公司權益為$1,050,000（含股本$300,000，保 留盈餘$750,000），甲公司於X2年12月31日以市價$550,000出售持股，致使其對乙公司之持股 比例降至30%，甲公司對乙公司仍具有重大影響。關於甲公司X2年個別財務報表上相關項目之金額， 下列敘述何者正確？', '["「權益法投資－投資乙公司」之期末餘額為$0", "「處分投資利益」金額為$16,000", "「權益法投資－投資乙公司」之期末餘額為$324,000", "「公允價值變動列入當期損益之金融資產－投資乙公司」之期末餘額為$330,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01727', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司有25,000股普通股全年流通在外，甲公司持有乙公司全年流通在外普通股10,000股之80%。 本年度乙公司之淨利為$100,000、合併淨利中歸屬於甲公司股東之金額為$200,000。此外，乙公司有 認股權全年流通在外，該認股權得以每股$15認購乙公司普通股2,000股，乙公司普通股全年平均市 價為$25。試問，合併稀釋每股盈餘為若干？', '["$8.93", "$8.00", "$7.76", "$7.63"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01728', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '中科公司在X1年初將一輛使用過的車輛捐贈給方圓慈善基金會，該車輛的成本為$1,000,000，X1年 初的帳面金額為$800,000，X1年初及X1年底的公允價值分別為$780,000及$600,000，則方圓慈善基 金會在X1年應認列之捐贈收入金額為何？', '["$1,000,000", "$800,000", "$780,000", "$600,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01729', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '昭明公司持有文選公司 80%股權，收購日文選公司各項可辨認資產、負債之帳面金額均等於公允價 值。昭明公司採權益法處理對文選公司之投資，X6 年底昭明公司帳上投資帳戶餘額為$650,000，文 選公司之權益包括股本$250,000（每股面額$10）、資本公積$80,000 及保留盈餘$70,000。文選公司 於X7年1月1日以每股$25增加發行新股5,000股，昭明公司取得其中4,000股，昭明公司於取得 新股後，帳上投資文選公司餘額為何？', '["$750,000", "$730,000", "$720,000", "$700,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01730', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '下列有關聯合控制資產之敘述，何者錯誤？', '["聯合控制資產之合資控制者提供或出資購買一項或多項資產，投入協議經營之事業", "聯合控制資產之合資並不設立公司、合夥或其他與合資控制者分離之組織", "每一合資控制者通常依其所享有聯合控制資產之份額，行使其權益", "合資控制者對聯合控制資產所分享之金額，認列為投資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01731', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X8年1月1日臺中公司及高雄公司分別投資$600,000及$400,000成立員林合資公司，雙方各取得60% 及40%股權，並同意未來損益按6：4分配。X8年12月31日員林公司財務報表顯示該公司之收入 為$1,800,000，成本與費用共計$1,600,000，流動資產為$600,000，建築物為$1,400,000，其他資產為 $200,000，流動負債為$300,000，長期負債為$500,000，普通股為$1,000,000，X8 年並未分配任何盈 餘。若臺中公司對於其投資於合資企業員林公司係採比例合併法處理，且臺中公司X8年12月31日 之建築物為$1,800,000，則臺中公司X8年12月31日以類別比例合併法編製之合併資產負債表上建 築物之金額為何？', '["$1,400,000", "$1,800,000", "$2,640,000", "$3,200,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01732', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '桃園公司於X4年8月15日投資新竹公司並取得控制。新竹公司對土地與房屋採重估價模式，新竹 公司於X2年4月1日取得房屋，並於X9年3月15日辦理重估價，則X9年12月31日將房屋由功 能性貨幣換算為表達貨幣時，依國際會計準則之規定，應選用那一日期的匯率？', '["X2年4月1日", "X4年8月15日", "X9年3月15日", "X9年12月31日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01733', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '苗栗公司於X1年11月2日向國外公司進口一批商品，價款為美元$100,000，雙方約定付款期限為 90天，為規避此外幣債務之匯兌風險，苗栗公司於X1年11月2日簽訂90天期、美元$100,000之 遠期外匯買入合約，相關之匯率資料如下： X1年11月2日    X1年12月31日 X2年1月30日 即期匯率    $32.42    $32.48  $32.52 遠期匯率 30天    $32.52    $32.54  $32.56 90天    $32.55    $32.57  $32.59 假設利率影響數微小，苗栗公司以新臺幣為功能性貨幣，上述所有交易對苗栗公司X1年度損益之影 響為何？', '["無影響", "損失$5,000", "損失$6,000", "損失$7,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01734', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '光華公司於X8年1月1日取得日本水上公司80%股權，取得當日水上公司可辨認淨資產之帳面金額 等於公允價值，且無合併商譽，水上公司權益包括股本￥5,000,000，保留盈餘￥2,000,000，匯率為', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL);
